"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[421],{3732:e=>{e.exports=JSON.parse('{"functions":[{"name":"saveinstance","desc":"Saves instances with specified options. Example:\\n```lua\\nlocal Params = {\\n\\tRepoURL = \\"https://raw.githubusercontent.com/RealSlimShady2000/SaveInstance420Edition/main/\\",\\n\\tSSI = \\"saveinstance\\",\\n}\\n\\nlocal synsaveinstance = loadstring(game:HttpGet(Params.RepoURL .. Params.SSI .. \\".luau\\", true), Params.SSI)()\\n\\nlocal CustomOptions = { SafeMode = true, timeout = 15, SaveBytecode = true }\\n\\nsynsaveinstance(CustomOptions)\\n```","params":[{"name":"Parameter_1","desc":"Can either be [SynSaveInstance.CustomOptions table] or a filled with instances ({Instance}), (then it will be treated as ExtraInstances with an invalid mode and IsModel will be true).","lua_type":"variant<table, table<Instance>>"},{"name":"Parameter_2","desc":"[OPTIONAL] If present, then Parameter_2 will be assumed to be [SynSaveInstance.CustomOptions table]. And then if the Parameter_1 is an Instance, then it will be assumed to be [SynSaveInstance.CustomOptions table].Object. If Parameter_1 is a table filled with instances ({Instance}), then it will be assumed to be [SynSaveInstance.CustomOptions table].ExtraInstances and IsModel will be true). This exists for sake compatibility with `saveinstance(game, {})`","lua_type":"table"}],"returns":[],"function_type":"static","yields":true,"source":{"line":1820,"path":"saveinstance.luau"}}],"properties":[],"types":[{"name":"CustomOptions table","desc":"* Structure of the main CustomOptions table.\\n* Note: Options are case-insensitive, meaning you could type `NilInstances` option as `nilInStaNces` and it would still be valid.\\nAnonymous {boolean|table{UserId = string, Name = string}} -- * **RISKY:** Cleans the file of any info related to your account like: Name, UserId. This is useful for some games that might store that info in GUIs or other Instances. Might potentially mess up parts of strings that contain characters that match your Name or parts of numbers that match your UserId. Can also be a table with UserId & Name keys. ___Default:___ false","fields":[{"name":"__DEBUG_MODE","lua_type":"boolean","desc":"This will print debug logs to console about unusual scenarios. Recommended to enable if you wish to help us improve our products and find bugs / issues with it! ___Default:___ false"},{"name":"ReadMe","lua_type":"boolean","desc":"___Default:___ true"},{"name":"SafeMode","lua_type":"boolean","desc":"Kicks you before Saving, which prevents you from being detected in any game. ___Default:___ false"},{"name":"ShutdownWhenDone","lua_type":"boolean","desc":"Shuts the game down after saveinstance is finished. ___Default:___ false"},{"name":"AntiIdle","lua_type":"boolean","desc":"Prevents the 20-minute-Idle Kick. ___Default:___ true"},{"name":"ShowStatus","lua_type":"boolean","desc":"___Default:___ true"},{"name":"Callback","lua_type":"function","desc":"If set, the serialized data will be sent to the callback function instead of to file. ___Default:___ false"},{"name":"mode","lua_type":"string","desc":"Valid modes: full, optimized, scripts. Change this to invalid mode like \\"invalid\\" if you only want ExtraInstances. \\"optimized\\" mode is **NOT** supported with *@Object* option. ___Default:___ `\\"optimized\\"`"},{"name":"noscripts","lua_type":"boolean","desc":"___Aliases:___ `Decompile`. ___Default:___ false"},{"name":"scriptcache","lua_type":"boolean","desc":"___Default:___ true"},{"name":"decomptype","lua_type":"string","desc":"* Deprecated. ___Default:___ Uses your executor\'s decompiler, if available."},{"name":"timeout","lua_type":"number","desc":"If the decompilation run time exceeds this value it gets cancelled. Set to -1 to disable timeout (unreliable). ***Aliases***: `DecompileTimeout`. ___Default:___ 10"},{"name":"DecompileJobless","lua_type":"boolean","desc":"Includes already decompiled code in the output. No new scripts are decompiled. ___Default:___ false"},{"name":"SaveBytecode","lua_type":"boolean","desc":"Includes bytecode in the output. Useful if you wish to be able to decompile it yourself later. ___Default:___ false"},{"name":"DecompileIgnore","lua_type":"{Instance | Instance.ClassName | [Instance.ClassName] = {Instance.Name}}","desc":"* Ignores match & it\'s descendants by default. To Ignore only the instance itself set the value to `= false`. Examples: \\"Chat\\", - Matches any instance with \\"Chat\\" ClassName, Players = {\\"MyPlayerName\\"} - Matches \\"Players\\" Class AND \\"MyPlayerName\\" Name ONLY, `workspace` - matches Instance by reference, `[workspace] = false` - matches Instance by reference and only ignores the instance itself and not it\'s descendants. ___Default:___ {TextChatService}"},{"name":"IgnoreList","lua_type":"{Instance | Instance.ClassName | [Instance.ClassName] = {Instance.Name}}","desc":"Structure is similar to **@DecompileIgnore** except `= false` meaning if you ignore one instance it will automatically ignore it\'s descendants. ___Default:___ {CoreGui, CorePackages}"},{"name":"ExtraInstances","lua_type":"{Instance}","desc":"If used with any invalid mode (like \\"invalidmode\\") it will only save these instances. ___Default:___ {}"},{"name":"IgnoreProperties","lua_type":"table","desc":"Ignores properties by Name. ___Default:___ {}"},{"name":"SaveCacheInterval","lua_type":"number","desc":"The less the value the more often it saves, but that would mean less performance due to constantly saving. ___Default:___ 0x1600 * 10"},{"name":"FilePath","lua_type":"string","desc":"Must only contain the name of the file, no file extension. ___Default:___ false"},{"name":"Object","lua_type":"Instance","desc":"* If provided, saves as .rbxmx (Model file) instead. If Object is game, it will be saved as a .rbxl file. **MUST BE AN INSTANCE REFERENCE, FOR EXAMPLE - *game.Workspace***. `\\"optimized\\"` mode is **NOT** supported with this option. If IsModel is set to false then Object specified here will be saved as a place file. ___Default:___ false"},{"name":"IsModel","lua_type":"boolean","desc":"If Object is specified then sets to true automatically, unless you set it to false. ___Default:___ false"},{"name":"NilInstances","lua_type":"boolean","desc":"Save instances that aren\'t Parented (Parented to nil). ___Default:___ false"},{"name":"NilInstancesFixes","lua_type":"{[Instance.ClassName] = function}","desc":"* This can cause some Classes to be fixed even though they might not need the fix (better be safe than sorry though). For example, Bones inherit from Attachment if we dont define them in the NilInstancesFixes then this will catch them anyways. **TO AVOID THIS BEHAVIOR USE THIS EXAMPLE:** {ClassName_That_Doesnt_Need_Fix = false}. ___Default:___ {Animator = function, AdPortal = function, BaseWrap = function, Attachment = function}"},{"name":"IgnoreDefaultProperties","lua_type":"boolean","desc":"Ignores default properties during saving.  ___Default:___ true"},{"name":"IgnoreNotArchivable","lua_type":"boolean","desc":"Ignores the Archivable property and saves Non-Archivable instances. ___Default:___ true"},{"name":"IgnorePropertiesOfNotScriptsOnScriptsMode","lua_type":"boolean","desc":"Ignores property of every instance that is not a script in \\"scripts\\" mode. ___Default:___ false"},{"name":"IgnoreSpecialProperties","lua_type":"boolean","desc":"Prevents calls to `gethiddenproperty` and uses fallback methods instead. This also helps with crashes. If your file is corrupted after saving, you can try turning this on. ___Default:___ false"},{"name":"UseUGCValidationService","lua_type":"boolean","desc":"* When `false`, the script never uses `UGCValidationService:GetPropertyValue` as a hidden-property fallback (some executors flag or lack it). `gethiddenproperty` is still used; only the UGC fallback is disabled. ___Default:___ true"},{"name":"IsolateLocalPlayer","lua_type":"boolean","desc":"Saves Children of LocalPlayer as separate folder and prevents any instance of ClassName Player with .Name identical to LocalPlayer.Name from saving. ___Default:___ false"},{"name":"IsolateStarterPlayer","lua_type":"boolean","desc":"If enabled, StarterPlayer will be cleared and the saved starter player will be placed into folders. ___Default:___ false"},{"name":"IsolateLocalPlayerCharacter","lua_type":"boolean","desc":"Saves Children of LocalPlayer.Character as separate folder and prevents any instance of ClassName Player with .Name identical to LocalPlayer.Name from saving. ___Default:___ false"},{"name":"RemovePlayerCharacters","lua_type":"boolean","desc":"Ignore player characters while saving. (Enables SaveNotCreatable automatically). ___Default:___ true"},{"name":"SaveNotCreatable","lua_type":"boolean","desc":"* Includes non-serializable instances as Folder objects (Name is misleading as this is mostly a fix for certain NilInstances and isn\'t always related to NotCreatable). ___Default:___ false"},{"name":"NotCreatableFixes","lua_type":"table<Instance.ClassName>","desc":"* {\\"Player\\"} is the same as {Player = \\"Folder\\"}; Format like {SpawnLocation = \\"Part\\"} is only to be used when SpawnLocation inherits from \\"Part\\" AND \\"Part\\" is Creatable. ___Default:___ { \\"\\", \\"Player\\", \\"PlayerScripts\\", \\"PlayerGui\\", \\"TouchTransmitter\\" }"},{"name":"IsolatePlayers","lua_type":"boolean","desc":"* This option does save players, it\'s just they won\'t show up in Studio and can only be viewed through the place file code (in text editor). More info at https://github.com/luau/UniversalSynSaveInstance/issues/2. ___Default:___ false"},{"name":"AlternativeWritefile","lua_type":"boolean","desc":"* Splits file content string into segments and writes them using appendfile. This might help with crashes when it starts writing to file. Though there is a risk of appendfile working incorrectly on some executors. ___Default:___ true"},{"name":"IgnoreDefaultPlayerScripts","lua_type":"boolean","desc":"* **RISKY: Ignores Default PlayerScripts like PlayerModule & RbxCharacterSounds. Prevents crashes on certain Executors. ___Default:___ true"},{"name":"IgnoreSharedStrings","lua_type":"boolean","desc":"* **RISKY: FIXES CRASHES (TEMPORARY, TESTED ON ROEXEC ONLY). FEEL FREE TO DISABLE THIS TO SEE IF IT WORKS FOR YOU**. ___Default:___ true"},{"name":"SharedStringOverwrite","lua_type":"boolean","desc":"* **RISKY:** if the process is not finished aka crashed then none of the affected values will be available. SharedStrings can also be used for ValueTypes that aren\'t `SharedString`, this behavior is not documented anywhere but makes sense (Could create issues though, due to _potential_ ValueType mix-up, only works on certain types which are all base64 encoded so far). Reason: Allows for potential smaller file size (can also be bigger in some cases). ___Default:___ false"},{"name":"TreatUnionsAsParts","lua_type":"boolean","desc":"* **RISKY:** Converts all UnionOperations to Parts. Useful if your Executor isn\'t able to save (read) Unions, because otherwise they will be invisible. ___Default:___ false (except Solara)"},{"name":"SetStreaming","lua_type":"boolean","desc":"* Before saving, force-loads an entire `StreamingEnabled` map into memory so saveinstance captures the WHOLE map instead of only the chunks near you. Pins loaded content (`ModelStreamingMode = Persistent`) so nothing streams back out, then sweeps a grid with `RequestStreamAroundAsync`. Can be slow and laggy on large maps. ___Aliases:___ `Streaming`. ___Default:___ false"},{"name":"StreamingAreaSize","lua_type":"number","desc":"* Side length (studs) of the square area swept around your starting position when `SetStreaming` is on. ___Default:___ 10000"},{"name":"StreamingRadius","lua_type":"number","desc":"* Per-request stream radius. Auto-uses the game\'s `StreamingTargetRadius` when readable. ___Default:___ 1024"},{"name":"StreamingTimeout","lua_type":"number","desc":"* Seconds to wait per `RequestStreamAroundAsync` request. ___Default:___ 20"},{"name":"StreamingConcurrency","lua_type":"number|boolean","desc":"* How many stream requests are kept in flight at once (higher = faster, more load). `false` = auto-scale to the grid size. ___Default:___ false (auto)"},{"name":"StreamingSlices","lua_type":"number","desc":"* Vertical layers swept per grid cell; raise for tall maps. ___Default:___ 2"},{"name":"StreamingMaxTime","lua_type":"number|boolean","desc":"* Overall seconds cap for the streaming sweep. It gives up on stuck/empty chunks (common on ocean-heavy maps where `RequestStreamAroundAsync` hangs) and proceeds. `false` = auto-scale to the grid size (bigger maps get a longer cap, 60s\u201315m). Set a number to force it. ___Default:___ false (auto)"},{"name":"StreamingChunkWait","lua_type":"number","desc":"* Max seconds to wait for one chunk to finish loading. The sweep waits until a region stops gaining parts (stability detection), capped here \u2014 dense regions load fully, empty ones return fast. ___Default:___ 12"},{"name":"StreamingSettleTime","lua_type":"number","desc":"* Seconds to wait after the streaming sweep for in-flight background terrain/loads to finish before saving. Also caps the post-sweep terrain-stabilization poll (waits until SmoothGrid stops growing) so terrain fills in instead of leaving floating islands. ___Default:___ 5"},{"name":"NeutralizeLighting","lua_type":"boolean","desc":"* Reset `Lighting` (ClockTime/Fog/Ambient), `Atmosphere`, post-effects (ColorCorrection/Bloom/Blur/SunRays/DoF) and clouds to clean midday right before saving, so the place opens BRIGHT instead of inheriting the game\'s dark/foggy/night atmosphere (the \\"all grey on the camera\\" look). `false` keeps the game\'s real lighting. ___Default:___ false"},{"name":"ExportObj","lua_type":"boolean","desc":"* Also write a world-space `.obj` of all MeshPart geometry next to the save. Geometry is recovered with `AssetService:CreateEditableMeshAsync`, which works even for PRIVATE game meshes that Studio can\'t re-download (those save as grey boxes). The `.obj` (with per-part vertex colors) opens in Blender or Studio\'s 3D importer. MeshParts can\'t be made to render inside the place file itself, so this is the only way to recover their visuals. Best paired with `SetStreaming` (load the whole map first). World-space baking duplicates reused meshes, so big maps produce large files. ___Default:___ false"},{"name":"Debug","lua_type":"boolean","desc":"* Writes a detailed run log to `saveinstance-debug.txt` in the executor workspace (executor, capabilities, options, streaming/prepass/decompile stats, save result). Share it for diagnosis. ___Default:___ false"},{"name":"DecompilePrepass","lua_type":"boolean","desc":"* **RISKY:** Before saving, decompiles every client script in parallel via an external API (`api.lua.expert`) and pre-fills the decompile cache, so the save\'s decompile step is near-instant. Big speedup on script-heavy games. Sends script bytecode to a third-party API; needs `getscriptbytecode` + an HTTP request function. ___Default:___ false"},{"name":"PrepassConcurrency","lua_type":"number","desc":"* Parallel decompile requests kept in flight during the prepass. ___Default:___ 24"},{"name":"PrepassRateGap","lua_type":"number","desc":"* Minimum seconds between decompile-API requests (lua.expert rejects unthrottled bursts). Lower = faster if the API allows. ___Default:___ 0.12"},{"name":"PrepassApiUrl","lua_type":"string","desc":"* Endpoint used by the decompile prepass. ___Default:___ \\"https://api.lua.expert/decompile\\""},{"name":"PrepassMaxScripts","lua_type":"number","desc":"* Upper bound for `DecompilePrepass`. If the game has more than this many client scripts, the prepass is skipped and scripts decompile on-demand during the save instead. The gather is cheap, the workers are throttled (reading thousands of scripts\' bytecode no longer bursts/crashes), and decompiles are API-rate-limited, so this just avoids an absurdly long prepass on games so large the prepass would risk destabilizing an already memory-heavy client (e.g. Grow a Garden 2 with 25k+ scripts); those fall back to the stable on-demand decompile. ___Default:___ 6000"}],"source":{"line":1787,"path":"saveinstance.luau"}},{"name":"OptionsAliases","desc":"Aliases for the [SynSaveInstance.CustomOptions table].","fields":[{"name":"FilePath","lua_type":"string","desc":"FileName"},{"name":"IgnoreDefaultProperties","lua_type":"string","desc":"IgnoreDefaultProps"},{"name":"SaveNotCreatable","lua_type":"string","desc":"SaveNonCreatable"},{"name":"IsolatePlayers","lua_type":"string","desc":"SavePlayers"},{"name":"scriptcache","lua_type":"string","desc":"DecompileJobless"},{"name":"timeout","lua_type":"string","desc":"DecompileTimeout"},{"name":"IgnoreNotArchivable","lua_type":"string","desc":"IgnoreArchivable"},{"name":"RemovePlayerCharacters","lua_type":"string","desc":"INVERSE SavePlayerCharacters"}],"source":{"line":1799,"path":"saveinstance.luau"}}],"name":"SynSaveInstance","desc":"Represents the options for saving instances with custom settings using the synsaveinstance function.","source":{"line":1723,"path":"saveinstance.luau"}}')}}]);